function [Is,n] = DiodeFit(voltage, current)
   kTq=26e-3;  
    % log(I)=log(Is)+V/(kTq*n)      % linearized equation x=V, y=log(I)
    % y = Ax + B
    % B = log(Is)  and  A = 1/(kT/q*n)

    % linearize the equation
    y = log(current);
    x = voltage;

    % perform least squares curve fitting
    A = [x ones(size(x))];   % matrix for linear system of equations
    b = y;
    coeff = A\b;   % solve linear system of equations

    B = coeff(2);
    A = coeff(1);

    % calculate Is and n
    Is = exp(B);
    n = 1/(kTq*A);

end

